const token = $input.first().json.access_token;
if (typeof token !== 'string' || token.length === 0) throw new Error('eBay did not return an application token.');
return [
  { json: { token, partId: '7e893f29-068e-43e2-9c3c-b9ba2d9ed6db', query: 'ESP32 DevKit V1' } },
  { json: { token, partId: '5cfc4a97-32ef-45c3-9162-ec2a9094fd85', query: 'BME280 I2C sensor breakout' } },
];

const response = $input.item.json;
const query = $('Approved eBay part queries').item.json;
const listing = (response.itemSummaries ?? []).find((item) => item.buyingOptions?.includes('FIXED_PRICE') && item.estimatedAvailabilityStatus === 'IN_STOCK' && item.itemWebUrl && item.image?.imageUrl && Number(item.price?.value) > 0 && /^[A-Z]{3}$/.test(item.price?.currency ?? ''));
if (!listing) return [];
return [{ json: { ...query, itemId: listing.itemId, title: listing.title, itemWebUrl: listing.itemWebUrl, thumbnailUrl: listing.image.imageUrl.replace(/s-l\d+/, 's-l225'), price: Number(listing.price.value), currency: listing.price.currency } }];

const listing = $('Hash selected eBay listing').item.json;
const image = $input.item.binary?.thumbnail;
if (!image?.data) return [];
const mimeType = image.mimeType ?? 'image/jpeg';
if (!['image/avif', 'image/gif', 'image/jpeg', 'image/png', 'image/webp'].includes(mimeType)) throw new Error(`Unsupported thumbnail type: ${mimeType}`);
const observedAt = new Date();
const expiresAt = new Date(observedAt.getTime() + 24 * 60 * 60 * 1000);
const citation = { sourceUrl: listing.itemWebUrl, locator: 'eBay Browse API item summary', title: listing.title };
return [{ json: { version: 'v2', sourcePolicyId: 'ebay-browse-catalog', sourcePolicyRevision: 1, idempotencyKey: `ebay:${listing.itemId}:${observedAt.toISOString().slice(0, 10)}`, source: { externalId: `ebay:${listing.itemId}`, canonicalUrl: listing.itemWebUrl, title: listing.title, locator: citation.locator, contentHash: listing.contentHash, license: 'eBay Browse API data under configured developer terms', termsStatus: 'public-catalog', fetchedAt: observedAt.toISOString(), expiresAt: expiresAt.toISOString() }, chunks: [{ externalId: `ebay:${listing.itemId}:summary`, content: `${listing.title} — ${listing.currency} ${listing.price.toFixed(2)}.`, citation }], offers: [{ externalId: `ebay:${listing.itemId}:offer`, partId: listing.partId, provider: 'eBay', providerSku: listing.itemId, purchaseUrl: listing.itemWebUrl, availability: 'in_stock', price: listing.price, currency: listing.currency, thumbnailDataUrl: `data:${mimeType};base64,${image.data}`, observedAt: observedAt.toISOString(), expiresAt: expiresAt.toISOString(), sourceUrl: listing.itemWebUrl, citation }], cadAssets: [] } }];
